import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjTimeline } from "./OjTimeline";
export { OjTimeline };

/**
 * Create an instance of [[OjTimeline]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojTimeline(driver, By.id('my-oj-timeline'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojTimeline(driver: DriverLike, by: By): Promise<OjTimeline> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjTimeline
  if (!(webEl instanceof OjTimeline)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-timeline>`);
  }
  return webEl;
}

register("oj-timeline", OjTimeline);
